""""
EOF v1 validation code - Exported from evmone unit tests
"""

import pytest
from ethereum_test_tools import EOFTestFiller, EOFException, Opcodes as Op
from ethereum_test_tools.eof.v1 import Container, Section

REFERENCE_SPEC_GIT_PATH = "EIPS/eip-5450.md"
REFERENCE_SPEC_VERSION = "9c7c91bf7b9b7af9e76248f7921a03ddc17f99ef"

@pytest.mark.parametrize(
    "eof_code,expected_hex_bytecode,exception",
    [
        pytest.param(
              Container(
                name = 'EOFV1_0001',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 511 + Op.JUMPF[0], max_stack_height=512),
                    ],
              )
              ,
              "",
              None,
              id="jumpf_stack_overflow_variable_stack_0"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0002',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 511 + Op.JUMPF[1], max_stack_height=512),
                    Section.Code(code=Op.PUSH0 * 515 + Op.STOP, max_stack_height=515),
                    ],
              )
              ,
              "",
              EOFException.STACK_OVERFLOW,
              id="jumpf_stack_overflow_variable_stack_1"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0003',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 511 + Op.JUMPF[1], max_stack_height=512),
                    Section.Code(code=Op.PUSH0 * 514 + Op.STOP, max_stack_height=514),
                    ],
              )
              ,
              "",
              EOFException.STACK_OVERFLOW,
              id="jumpf_stack_overflow_variable_stack_2"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0004',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 1022 + Op.JUMPF[1], max_stack_height=1023),
                    Section.Code(code=Op.PUSH0 + Op.STOP, max_stack_height=1),
                    ],
              )
              ,
              "",
              None,
              id="jumpf_stack_overflow_variable_stack_3"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0005',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 1022 + Op.JUMPF[1], max_stack_height=1023),
                    Section.Code(code=Op.PUSH0 * 5 + Op.STOP, max_stack_height=5),
                    ],
              )
              ,
              "",
              EOFException.STACK_OVERFLOW,
              id="jumpf_stack_overflow_variable_stack_4"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0006',
                sections = [
                    Section.Code(code=Op.PUSH0 + Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH0 * 1022 + Op.JUMPF[1], max_stack_height=1023),
                    Section.Code(code=Op.PUSH0 * 2 + Op.STOP, max_stack_height=2),
                    ],
              )
              ,
              "",
              EOFException.STACK_OVERFLOW,
              id="jumpf_stack_overflow_variable_stack_5"
        ),
        
    ]
)

def test_example_valid_invalid(
    eof_test: EOFTestFiller,
    eof_code: Container,
    expected_hex_bytecode: str,
    exception: EOFException | None,
):
    """
    Verify eof container construction and exception
    """
    assert bytes(eof_code) == bytes.fromhex(expected_hex_bytecode)

    eof_test(
        data=eof_code,
        expect_exception=exception,
    )
